const test = require('node:test')
const assert = require('node:assert/strict')

const {
  defaultWorkspaceSettings,
  filterAgentsForWorkspace,
  readWorkspaceSettings,
} = require('./workspaceSettings')

test('readWorkspaceSettings falls back to defaults for invalid payloads', () => {
  const settings = readWorkspaceSettings('{\"showRuntimeAgents\":')

  assert.deepEqual(settings, defaultWorkspaceSettings)
})

test('readWorkspaceSettings merges stored booleans onto defaults', () => {
  const settings = readWorkspaceSettings(
    JSON.stringify({
      showRuntimeAgents: false,
      highlightActivity: false,
      autoOpenTasks: true,
    })
  )

  assert.deepEqual(settings, {
    showRuntimeAgents: false,
    highlightActivity: false,
    autoOpenTasks: true,
  })
})

test('filterAgentsForWorkspace keeps coordinator and primary agents when runtime agents are hidden', () => {
  const visibleAgents = filterAgentsForWorkspace(
    [
      { id: 'agent-main' },
      { id: 'planner' },
      { id: 'executor' },
      { id: 'reviewer' },
      { id: 'agent-worker-1' },
      { id: 'agent-worker-2' },
    ],
    {
      ...defaultWorkspaceSettings,
      showRuntimeAgents: false,
    }
  )

  assert.deepEqual(
    visibleAgents.map((agent) => agent.id),
    ['agent-main', 'planner', 'executor', 'reviewer']
  )
})
EOF"

